# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    public int health = 100;
    public int currency = 500;
    public int damage = 10;

    void Start()
    {
        // Initialize player stats if needed
    }

    public void TakeDamage(int amount)
    {
        health -= amount;
        if (health < 0) health = 0;
        Debug.Log("Player took " + amount + " damage. Remaining health: " + health);
    }

    public bool PurchaseItem(int price, int additionalDamage)
    {
        if (currency >= price)
        {
            currency -= price;
            damage += additionalDamage;
            Debug.Log("Purchased item for " + price + ". New damage: " + damage);
            return true;
        }
        else
        {
            Debug.Log("Not enough currency to purchase item.");
            return false;
        }
    }

    public void HealPlayer(int amount)
    {
        health += amount;
        if (health > 100) health = 100;
        Debug.Log("Healed " + amount + ". Current health: " + health);
    }

    public void AddCurrency(int amount)
    {
        currency += amount;
        Debug.Log("Added " + amount + " to currency. Total currency: " + currency);
    }
}